"""
app.py — versi deployment mandiri (self-contained) untuk Hugging Face Spaces.
HTML halaman dan gambar header sudah digabung ke dalam file ini, sehingga
TIDAK perlu folder templates/ atau static/. Cukup file-file datar di root:

    app.py
    requirements.txt
    Dockerfile
    README.md
    peekmyfruit_model.keras
    label_encoder.json
"""

import io
import json
from pathlib import Path

import numpy as np
from flask import Flask, jsonify, request
from PIL import Image
from tensorflow import keras

ROOT = Path(__file__).resolve().parent
MODEL_PATH = ROOT / "peekmyfruit_model.keras"
LABELS_PATH = ROOT / "label_encoder.json"
IMG_SIZE = (224, 224)
DISPLAY = {"unripe": "Mentah", "ripe": "Matang", "rotten": "Busuk"}

app = Flask(__name__)

print("Memuat model...")
model = keras.models.load_model(MODEL_PATH)
mapping = json.load(open(LABELS_PATH))
CLASS_NAMES = [mapping[str(i)] for i in range(len(mapping))]
print("Model siap. Kelas:", CLASS_NAMES)


def prepare(img):
    img = img.convert("RGB").resize(IMG_SIZE)
    return np.expand_dims(np.array(img, dtype="float32"), axis=0)


@app.route("/")
def index():
    return HTML_PAGE


@app.route("/predict", methods=["POST"])
def predict():
    if "image" not in request.files:
        return jsonify({"error": "Tidak ada gambar yang dikirim."}), 400
    try:
        img = Image.open(io.BytesIO(request.files["image"].read()))
    except Exception:
        return jsonify({"error": "File gambar tidak bisa dibaca."}), 400

    probs = model.predict(prepare(img), verbose=0)[0]
    idx = int(np.argmax(probs))
    label = CLASS_NAMES[idx]
    return jsonify({
        "label": label,
        "display": DISPLAY.get(label, label.capitalize()),
        "confidence": float(probs[idx]),
        "all": [
            {"label": CLASS_NAMES[i],
             "display": DISPLAY.get(CLASS_NAMES[i], CLASS_NAMES[i].capitalize()),
             "prob": float(probs[i])}
            for i in range(len(CLASS_NAMES))
        ],
    })


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=7860)


